class Build {
  name: string;
  hp: number;
  img: string;
  decay: number;

  constructor(name: string, hp: number, img: string, decay: number) {
    this.name = name;
    this.hp = hp;
    this.img = img;
    this.decay = decay;
  }
}

var SheetMetalDoor = new Build(
  "Sheet Metal Door",
  250,
  "https://img.craftpedia.net/caches/rust/door.hinged.metal/door.hinged.metal_512x512.webp",
  8
);

var GarageDoor = new Build(
  "Garage Door",
  600,
  "https://img.craftpedia.net/caches/rust/wall.frame.garagedoor/wall.frame.garagedoor_512x512.webp",
  8
);

export var buildings: object[] = [SheetMetalDoor, GarageDoor];
